import { BOTS } from '../utils/constants';
import styles from './BotSelector.module.css';

export default function BotSelector({ selectedBot, onSelect }) {
  return (
    <div className={styles.panel}>
      <div className={styles.title}>🤖 Bot Stratejileri</div>
      {BOTS.map(bot => (
        <div
          key={bot.id}
          className={`${styles.card} ${bot.id === selectedBot ? styles.selected : ''}`}
          onClick={() => onSelect(bot.id)}
          style={{ '--bot-color': bot.color }}
        >
          <div className={styles.cardHeader}>
            <div className={styles.botName}>{bot.name}</div>
            <div className={styles.badge} style={{ color: bot.color, borderColor: bot.color }}>
              {bot.successRate}%
            </div>
          </div>
          <div className={styles.desc}>{bot.desc}</div>
          <div className={styles.stats}>
            <span>İşlem: <b>{bot.trades}</b></span>
            <span>Başarı: <b style={{ color: bot.color }}>{bot.successRate}%</b></span>
          </div>
        </div>
      ))}
    </div>
  );
}
